import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"System Administration","description":"","frontmatter":{},"headers":[],"relativePath":"modules/system-administration.md","filePath":"modules/system-administration.md"}'),d={name:"modules/system-administration.md"};function i(s,t,n,l,c,m){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="system-administration" tabindex="-1">System Administration <a class="header-anchor" href="#system-administration" aria-label="Permalink to &quot;System Administration&quot;">​</a></h1><p>The System Administration module is the control centre of GeniusHRM. It provides super-admin and HR Manager level access to manage users, define roles and permissions, configure system-wide settings (branding, SMTP, SMS), and review a full audit trail of all actions taken across the platform.</p><p>Navigate to <strong>Administration</strong> in the left sidebar to access all four sections.</p><hr><h2 id="user-management" tabindex="-1">User Management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User Management&quot;">​</a></h2><p><strong>URL:</strong> <code>/admin/users</code><br><strong>Access:</strong> Admin only</p><p>User Management allows you to control who can log in to GeniusHRM and what role they hold.</p><h3 id="user-list" tabindex="-1">User List <a class="header-anchor" href="#user-list" aria-label="Permalink to &quot;User List&quot;">​</a></h3><p>The user index displays all system accounts in a searchable, filterable table:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Name</td><td>Full name of the user</td></tr><tr><td>Email</td><td>Login email address</td></tr><tr><td>Role</td><td>Assigned Spatie role badge</td></tr><tr><td>Status</td><td>Active (green) or Inactive (red)</td></tr><tr><td>Actions</td><td>Edit, Toggle Active, Reset Password</td></tr></tbody></table><p>Use the <strong>Search</strong> field to find users by name or email. Use the <strong>Role</strong> dropdown to filter by role.</p><h3 id="creating-a-user" tabindex="-1">Creating a User <a class="header-anchor" href="#creating-a-user" aria-label="Permalink to &quot;Creating a User&quot;">​</a></h3><ol><li>Click <strong>Add User</strong> (top-right).</li><li>Fill in the form: <ul><li><strong>Name</strong> — full name</li><li><strong>Email</strong> — must be unique</li><li><strong>Password</strong> — minimum 8 characters (shown/hidden toggle)</li><li><strong>Role</strong> — select from available roles</li></ul></li><li>Click <strong>Create User</strong>.</li></ol><p>The new user can immediately log in at <code>/login</code>.</p><div class="tip custom-block"><p class="custom-block-title">Linking to an Employee</p><p>After creating a user account, link it to the corresponding employee record by editing the employee and assigning the <code>user_id</code>. This enables features like self-service leave requests and payslip access.</p></div><h3 id="editing-a-user" tabindex="-1">Editing a User <a class="header-anchor" href="#editing-a-user" aria-label="Permalink to &quot;Editing a User&quot;">​</a></h3><p>Click <strong>Edit</strong> on any user row. You can update:</p><ul><li>Name and email</li><li>Role assignment</li><li>Password (leave blank to keep existing password)</li></ul><h3 id="activating-deactivating-users" tabindex="-1">Activating / Deactivating Users <a class="header-anchor" href="#activating-deactivating-users" aria-label="Permalink to &quot;Activating / Deactivating Users&quot;">​</a></h3><p>Click <strong>Toggle Active</strong> on any user row. A confirmation modal appears before the change is applied.</p><ul><li><strong>Deactivated users</strong> cannot log in but their data is preserved.</li><li>All their historical records (audit logs, payslips, leave requests) remain intact.</li></ul><div class="warning custom-block"><p class="custom-block-title">Core Account Protection</p><p>The primary Admin account cannot be deactivated. Attempting to do so will return a permission error.</p></div><h3 id="resetting-passwords" tabindex="-1">Resetting Passwords <a class="header-anchor" href="#resetting-passwords" aria-label="Permalink to &quot;Resetting Passwords&quot;">​</a></h3><p>Click <strong>Reset Password</strong> on any user row. After confirmation, the user&#39;s password is reset to the system default: <code>Admin@1234</code>.</p><p>Instruct the user to change their password immediately after next login.</p><hr><h2 id="roles-permissions" tabindex="-1">Roles &amp; Permissions <a class="header-anchor" href="#roles-permissions" aria-label="Permalink to &quot;Roles &amp; Permissions&quot;">​</a></h2><p><strong>URL:</strong> <code>/admin/roles</code><br><strong>Access:</strong> Admin only</p><p>GeniusHRM uses Spatie&#39;s role-permission package. Roles are assigned to users, and permissions are assigned to roles. The Roles &amp; Permissions page provides a visual matrix to manage this.</p><h3 id="built-in-roles" tabindex="-1">Built-in Roles <a class="header-anchor" href="#built-in-roles" aria-label="Permalink to &quot;Built-in Roles&quot;">​</a></h3><p>Six core roles are pre-configured and cannot be renamed or deleted:</p><table tabindex="0"><thead><tr><th>Role</th><th>Typical User</th><th>Access Level</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>System administrator</td><td>Full access to all modules and settings</td></tr><tr><td><strong>HR Manager</strong></td><td>Head of HR department</td><td>Full HR access; no system settings</td></tr><tr><td><strong>Manager</strong></td><td>Department/team lead</td><td>View own team; approve leaves/attendance</td></tr><tr><td><strong>Employee</strong></td><td>Regular staff member</td><td>Self-service only (own profile, payslip, leave)</td></tr><tr><td><strong>Recruiter</strong></td><td>Recruitment specialist</td><td>Recruitment &amp; ATS module only</td></tr><tr><td><strong>Finance</strong></td><td>Finance/payroll team</td><td>Payroll and compensation module</td></tr></tbody></table><p>Core roles display a <strong>lock icon</strong> — their names cannot be edited and they cannot be deleted.</p><h3 id="permission-categories" tabindex="-1">Permission Categories <a class="header-anchor" href="#permission-categories" aria-label="Permalink to &quot;Permission Categories&quot;">​</a></h3><p>Permissions are grouped by module prefix. Each permission follows the naming convention <code>module.action</code>:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Example Permissions</th></tr></thead><tbody><tr><td><code>employees</code></td><td><code>employees.view</code>, <code>employees.create</code>, <code>employees.edit</code>, <code>employees.delete</code></td></tr><tr><td><code>payroll</code></td><td><code>payroll.view</code>, <code>payroll.run</code>, <code>payroll.approve</code></td></tr><tr><td><code>leave</code></td><td><code>leave.view</code>, <code>leave.approve</code>, <code>leave.manage</code></td></tr><tr><td><code>attendance</code></td><td><code>attendance.view</code>, <code>attendance.manage</code></td></tr><tr><td><code>recruitment</code></td><td><code>recruitment.view</code>, <code>recruitment.manage</code></td></tr><tr><td><code>performance</code></td><td><code>performance.view</code>, <code>performance.manage</code>, <code>performance.finalise</code></td></tr><tr><td><code>training</code></td><td><code>training.view</code>, <code>training.manage</code></td></tr><tr><td><code>documents</code></td><td><code>documents.view</code>, <code>documents.manage</code></td></tr><tr><td><code>reports</code></td><td><code>reports.view</code></td></tr><tr><td><code>admin</code></td><td><code>admin.users</code>, <code>admin.roles</code>, <code>admin.settings</code></td></tr></tbody></table><h3 id="permission-matrix" tabindex="-1">Permission Matrix <a class="header-anchor" href="#permission-matrix" aria-label="Permalink to &quot;Permission Matrix&quot;">​</a></h3><p>The right panel of the Roles page shows a permission matrix:</p><ol><li><strong>Select a role</strong> from the left panel.</li><li>The right panel loads all permissions grouped by module.</li><li>Each module group has a <strong>Select All</strong> checkbox at the top.</li><li>Check/uncheck individual permissions.</li><li>Click <strong>Save Permissions</strong> to apply.</li></ol><p>Changes take effect immediately — no server restart required.</p><h3 id="creating-custom-roles" tabindex="-1">Creating Custom Roles <a class="header-anchor" href="#creating-custom-roles" aria-label="Permalink to &quot;Creating Custom Roles&quot;">​</a></h3><ol><li>Click <strong>Add Role</strong> (top of the left panel).</li><li>Enter a role name (e.g. <code>Accountant</code>, <code>Intern</code>, <code>Payroll Clerk</code>).</li><li>Click <strong>Create</strong>.</li><li>The new role appears in the list — click it to assign permissions.</li></ol><h3 id="deleting-custom-roles" tabindex="-1">Deleting Custom Roles <a class="header-anchor" href="#deleting-custom-roles" aria-label="Permalink to &quot;Deleting Custom Roles&quot;">​</a></h3><p>Custom roles (non-core) can be deleted if they have <strong>zero users</strong> assigned. Click the delete icon next to the role name. A confirmation modal appears before deletion.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleting a role with users assigned will fail. Reassign all users to a different role first.</p></div><hr><h2 id="system-settings" tabindex="-1">System Settings <a class="header-anchor" href="#system-settings" aria-label="Permalink to &quot;System Settings&quot;">​</a></h2><p><strong>URL:</strong> <code>/admin/settings</code><br><strong>Access:</strong> Admin only</p><p>System Settings is organised into six tabs. All settings are stored in the <code>system_settings</code> database table as key-value pairs and take effect immediately.</p><h3 id="general-tab" tabindex="-1">General Tab <a class="header-anchor" href="#general-tab" aria-label="Permalink to &quot;General Tab&quot;">​</a></h3><p>Core organisation information:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Organisation Name</td><td>Displayed in reports and documents</td></tr><tr><td>Organisation Email</td><td>Default sender/reply-to for system emails</td></tr><tr><td>Phone</td><td>Contact number for official documents</td></tr><tr><td>Address</td><td>Used in payslips and company documents</td></tr></tbody></table><h3 id="appearance-tab" tabindex="-1">Appearance Tab <a class="header-anchor" href="#appearance-tab" aria-label="Permalink to &quot;Appearance Tab&quot;">​</a></h3><p>Controls the look and feel of the application:</p><p><strong>App Name</strong> The name displayed in the browser tab title and sidebar heading. Defaults to <code>GeniusHRM</code>.</p><p><strong>Footer Copyright Text</strong> Text shown at the bottom of the sidebar on every page. Example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>© 2026 Acme Corp. All rights reserved.</span></span></code></pre></div><p><strong>Logo Upload</strong> Upload your company logo (PNG, JPG, SVG, WebP — max 2 MB). Once uploaded:</p><ul><li>The logo appears in the top-left of the sidebar replacing the default icon.</li><li>Stored at <code>storage/app/public/branding/</code>.</li><li>Accessible via <code>/storage/branding/filename.ext</code>.</li></ul><div class="tip custom-block"><p class="custom-block-title">Best Logo Size</p><p>Use an image with a height of 28–40px or a square format. Transparent PNG or SVG works best on both light and dark backgrounds.</p></div><h3 id="regional-tab" tabindex="-1">Regional Tab <a class="header-anchor" href="#regional-tab" aria-label="Permalink to &quot;Regional Tab&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Options</th></tr></thead><tbody><tr><td>Timezone</td><td>UTC, Europe/London, Asia/Dhaka, America/New_York, and 10+ others</td></tr><tr><td>Date Format</td><td>YYYY-MM-DD, DD/MM/YYYY, MM/DD/YYYY, Mon DD YYYY</td></tr><tr><td>Currency</td><td>USD, EUR, GBP, BDT, AED, etc.</td></tr><tr><td>Currency Symbol</td><td>$, €, £, ৳, ﷼, etc.</td></tr></tbody></table><h3 id="payroll-tab" tabindex="-1">Payroll Tab <a class="header-anchor" href="#payroll-tab" aria-label="Permalink to &quot;Payroll Tab&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Financial Year Start</td><td>Month number (1 = January, 4 = April, 7 = July)</td></tr></tbody></table><p>This controls which month is used as the start of financial year in payroll reports.</p><h3 id="email-smtp-tab" tabindex="-1">Email (SMTP) Tab <a class="header-anchor" href="#email-smtp-tab" aria-label="Permalink to &quot;Email (SMTP) Tab&quot;">​</a></h3><p>Configure outgoing email for notifications, password resets, and payslip delivery.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Mailer</td><td><code>smtp</code> (recommended), <code>sendmail</code>, <code>log</code> (dev)</td></tr><tr><td>Host</td><td>SMTP server hostname</td></tr><tr><td>Port</td><td>Usually <code>587</code> (TLS) or <code>465</code> (SSL)</td></tr><tr><td>Username</td><td>SMTP username / email address</td></tr><tr><td>Password</td><td>SMTP password (stored encrypted)</td></tr><tr><td>Encryption</td><td><code>tls</code>, <code>ssl</code>, or none</td></tr><tr><td>From Address</td><td>Sender email shown to recipients</td></tr><tr><td>From Name</td><td>Sender name (e.g. &quot;GeniusHRM Notifications&quot;)</td></tr></tbody></table><p><strong>Common SMTP Providers:</strong></p><table tabindex="0"><thead><tr><th>Provider</th><th>Host</th><th>Port</th><th>Encryption</th></tr></thead><tbody><tr><td>Gmail</td><td>smtp.gmail.com</td><td>587</td><td>TLS</td></tr><tr><td>Mailgun</td><td>smtp.mailgun.org</td><td>587</td><td>TLS</td></tr><tr><td>Mailtrap (dev)</td><td>sandbox.smtp.mailtrap.io</td><td>2525</td><td>TLS</td></tr><tr><td>SendGrid</td><td>smtp.sendgrid.net</td><td>587</td><td>TLS</td></tr><tr><td>Outlook/365</td><td>smtp.office365.com</td><td>587</td><td>STARTTLS</td></tr></tbody></table><p><strong>Send Test Email</strong><br> After saving SMTP settings, use the test email field at the bottom of the tab. Enter any email address and click <strong>Send Test</strong>. You will see an immediate success or error message — no page reload required.</p><h3 id="sms-tab" tabindex="-1">SMS Tab <a class="header-anchor" href="#sms-tab" aria-label="Permalink to &quot;SMS Tab&quot;">​</a></h3><p>Configure outgoing SMS notifications (optional).</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Provider</td><td>Twilio, Nexmo, Vonage, Africa&#39;s Talking, Custom</td></tr><tr><td>API Key</td><td>Provider API key or Account SID</td></tr><tr><td>API Secret</td><td>Provider auth token or API secret</td></tr><tr><td>From</td><td>Sender number or name</td></tr><tr><td>SMS Enabled</td><td>Toggle to enable/disable SMS globally</td></tr></tbody></table><p><strong>Provider-specific notes:</strong></p><p><strong>Twilio:</strong></p><ul><li>API Key = Account SID (starts with <code>AC...</code>)</li><li>API Secret = Auth Token</li><li>From = Twilio phone number (e.g. <code>+14155552671</code>)</li></ul><p><strong>Nexmo / Vonage:</strong></p><ul><li>API Key = Vonage API key</li><li>API Secret = Vonage API secret</li><li>From = Alphanumeric sender name (max 11 chars) or phone number</li></ul><p><strong>Africa&#39;s Talking:</strong></p><ul><li>API Key = Username</li><li>API Secret = API key from dashboard</li><li>From = Shortcode or sender ID</li></ul><div class="warning custom-block"><p class="custom-block-title">SMS Billing</p><p>SMS usage is billed by your provider. Enable SMS only after confirming your account has credits and the correct sender ID is approved.</p></div><hr><h2 id="audit-log" tabindex="-1">Audit Log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit Log&quot;">​</a></h2><p><strong>URL:</strong> <code>/admin/audit-log</code><br><strong>Access:</strong> Admin, HR Manager</p><p>The Audit Log records every significant action taken in GeniusHRM: who did what, in which module, and when. It is immutable — entries cannot be edited or deleted.</p><h3 id="what-gets-logged" tabindex="-1">What Gets Logged <a class="header-anchor" href="#what-gets-logged" aria-label="Permalink to &quot;What Gets Logged&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>Logged Actions</th></tr></thead><tbody><tr><td>Employees</td><td>Created, updated, deleted</td></tr><tr><td>Payroll</td><td>Run created, approved, paid; payslip generated</td></tr><tr><td>Leave</td><td>Request submitted, approved, rejected</td></tr><tr><td>Recruitment</td><td>Job posted, candidate status changed, offer made</td></tr><tr><td>Performance</td><td>Cycle created, rating submitted, finalised</td></tr><tr><td>Training</td><td>Course created, enrollment, completion</td></tr><tr><td>Documents</td><td>Uploaded, acknowledged, deleted</td></tr><tr><td>Settings</td><td>System settings updated, logo changed</td></tr><tr><td>Users</td><td>Created, role changed, deactivated, password reset</td></tr><tr><td>Roles</td><td>Permissions updated, custom role created/deleted</td></tr></tbody></table><h3 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h3><p>Use the filter bar at the top of the Audit Log to narrow down entries:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Description</th></tr></thead><tbody><tr><td>User</td><td>Filter by who performed the action</td></tr><tr><td>Module</td><td>Filter by module name (Employees, Payroll, etc.)</td></tr><tr><td>Date From</td><td>Start of date range</td></tr><tr><td>Date To</td><td>End of date range</td></tr><tr><td>Search</td><td>Text search in the description field</td></tr></tbody></table><h3 id="log-entry-fields" tabindex="-1">Log Entry Fields <a class="header-anchor" href="#log-entry-fields" aria-label="Permalink to &quot;Log Entry Fields&quot;">​</a></h3><p>Each entry displays:</p><ul><li><strong>Timestamp</strong> — exact date and time</li><li><strong>User</strong> — name of the user who performed the action</li><li><strong>Module</strong> — which module was affected</li><li><strong>Action</strong> — colour-coded badge (created = green, updated = blue, deleted = red, approved = teal)</li><li><strong>Description</strong> — human-readable summary of what changed</li></ul><h3 id="exporting-to-csv" tabindex="-1">Exporting to CSV <a class="header-anchor" href="#exporting-to-csv" aria-label="Permalink to &quot;Exporting to CSV&quot;">​</a></h3><p>Click <strong>Export CSV</strong> (top-right). The export respects all active filters — only the currently filtered entries are exported.</p><p>The CSV includes: <code>id</code>, <code>timestamp</code>, <code>user_name</code>, <code>module</code>, <code>action</code>, <code>description</code>, <code>ip_address</code>.</p><div class="tip custom-block"><p class="custom-block-title">Compliance Use</p><p>The Audit Log CSV export is useful for compliance audits, security reviews, and incident investigations. Store exports securely as they may contain sensitive user activity data.</p></div><h3 id="log-retention" tabindex="-1">Log Retention <a class="header-anchor" href="#log-retention" aria-label="Permalink to &quot;Log Retention&quot;">​</a></h3><p>By default, all audit log entries are retained indefinitely. For high-traffic systems, consider adding a scheduled command to archive or delete entries older than your retention policy (e.g. 2 years).</p><hr><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>Recommendation</th></tr></thead><tbody><tr><td>Default passwords</td><td>Change all demo account passwords immediately after installation</td></tr><tr><td>Admin account</td><td>Use a strong, unique password; enable 2FA if configured</td></tr><tr><td>SMTP password</td><td>Use an app-specific password, not your main account password</td></tr><tr><td>SMS secrets</td><td>Rotate API keys periodically from your provider dashboard</td></tr><tr><td>Audit log</td><td>Review weekly for unexpected admin actions</td></tr><tr><td>User deactivation</td><td>Deactivate accounts promptly when staff leave</td></tr><tr><td>Role assignment</td><td>Follow least-privilege — assign the most restrictive role that meets the user&#39;s needs</td></tr></tbody></table>',103)])])}const g=e(d,[["render",i]]);export{p as __pageData,g as default};
